{"path": "/tmp/sv-dcda7e90d4fb4b43ae8b952b29f26a8a/Components/CheckoutWizard.razor", "file_text": "<h3>Checkout</h3>

@if (currentStep == 1)
{
    <ShippingStep Shipping="order.Shipping"
                  ShippingChanged="OnShippingChanged"
                  OnNext="GoToPayment" />
}
else
{
    <PaymentStep Payment="order.Payment"
                 PaymentChanged="OnPaymentChanged"
                 OnBack="GoToShipping"
                 OnPlaceOrder="PlaceOrder" />
}

@code {
    /// <summary>Raised when the user completes the wizard and places the order.</summary>
    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order order = new();
    private int currentStep = 1;

    private void OnShippingChanged(ShippingInfo shipping)
    {
        order.Shipping = shipping;
    }

    private void OnPaymentChanged(PaymentInfo payment)
    {
        order.Payment = payment;
    }

    private void GoToPayment()
    {
        currentStep = 2;
    }

    private void GoToShipping()
    {
        currentStep = 1;
    }

    private async Task PlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(order);
    }
}
"}

{"path": "/tmp/sv-dcda7e90d4fb4b43ae8b952b29f26a8a/Components/ShippingStep.razor", "file_text": "<h4>Shipping Information</h4>

<div class="mb-3">
    <label>Name</label>
    <input class="form-control" value="@Shipping.Name"
           @onchange="e => Update(s => s.Name = e.Value?.ToString() ?? "")" />
</div>

<div class="mb-3">
    <label>Address</label>
    <input class="form-control" value="@Shipping.Address"
           @onchange="e => Update(s => s.Address = e.Value?.ToString() ?? "")" />
</div>

<div class="mb-3">
    <label>City</label>
    <input class="form-control" value="@Shipping.City"
           @onchange="e => Update(s => s.City = e.Value?.ToString() ?? "")" />
</div>

<div class="mb-3">
    <label>Zip Code</label>
    <input class="form-control" value="@Shipping.ZipCode"
           @onchange="e => Update(s => s.ZipCode = e.Value?.ToString() ?? "")" />
</div>

@if (!string.IsNullOrWhiteSpace(validationMessage))
{
    <div class="text-danger mb-2">@validationMessage</div>
}

<button class="btn btn-primary" @onclick="TryNext">Next</button>

@code {
    [Parameter, EditorRequired]
    public ShippingInfo Shipping { get; set; } = new();

    [Parameter]
    public EventCallback<ShippingInfo> ShippingChanged { get; set; }

    [Parameter]
    public EventCallback OnNext { get; set; }

    private string? validationMessage;

    private async Task Update(Action<ShippingInfo> apply)
    {
        apply(Shipping);
        await ShippingChanged.InvokeAsync(Shipping);
    }

    private async Task TryNext()
    {
        if (string.IsNullOrWhiteSpace(Shipping.Name) || string.IsNullOrWhiteSpace(Shipping.Address))
        {
            validationMessage = "Name and Address are required.";
            return;
        }

        validationMessage = null;
        await OnNext.InvokeAsync();
    }
}
"}

